/**
 * 자동 예외 콘솔 — WMS Phase 1
 *
 * admin 전용. 운영 메뉴의 "자동 예외" 진입점.
 *
 * 동작:
 *   - /api/tasks?autoGenerated=true 로 자동 카드 목록 조회
 *   - 카드 클릭 → 상세 (context JSONB pretty print + recipients + 첨부 메타)
 *   - 본인 recipient done 처리 (PATCH /api/tasks/:id { status:'done', completionNote })
 *   - 라우팅 표 미리보기 (/api/exception-routing)
 *   - mock trigger (POST /api/exception-routing/mock) — Week 3 검증용
 *
 * 정책:
 *   - 가격/배송/라벨/외부 API 일체 호출 안 함.
 *   - context 는 백엔드에서 redact 통과한 값 — 그대로 표시.
 */
(function () {
  let user = null;
  let cards = [];
  let routing = [];
  let openTaskId = null;

  function esc(s) {
    if (s == null) return '';
    return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }
  function fmtDate(iso) { return iso ? new Date(iso).toLocaleString('ko-KR') : '-'; }

  const SEVERITY_COLORS = {
    low:      { bg: '#37474f', fg: '#90a4ae' },
    medium:   { bg: '#1a3a4a', fg: '#64b5f6' },
    high:     { bg: '#5d3a00', fg: '#ffb74d' },
    critical: { bg: '#4a1a1a', fg: '#ef9a9a' },
  };

  async function load() {
    if (!user) user = window.__pmcUser || (await fetch('/api/auth/me').then(r => r.json())).user;
    const el = document.getElementById('page-exception-tasks');
    if (!user || !user.isAdmin) {
      el.innerHTML = '<div style="padding:40px;color:#888;">관리자 전용 페이지입니다.</div>';
      return;
    }
    renderShell(el);
    await Promise.all([refresh(), loadRouting()]);
  }

  function renderShell(el) {
    el.innerHTML = `
      <div style="margin-bottom:16px;display:flex;justify-content:space-between;align-items:flex-end;flex-wrap:wrap;gap:10px;">
        <div>
          <h1 style="font-size:22px;color:#fff;">⚠️ 자동 예외 콘솔</h1>
          <p style="color:#888;font-size:13px;">자동화가 처리에 실패한 카드. 운영자(admin)에게 자동 라우팅 됨.</p>
        </div>
        <div style="display:flex;gap:8px;">
          <button id="ef-mock-btn" style="padding:8px 14px;background:#5d3a00;border:none;border-radius:6px;color:#ffb74d;cursor:pointer;font-size:12px;">🧪 Mock trigger</button>
          <button id="ef-refresh" style="padding:8px 14px;background:#37474f;border:none;border-radius:6px;color:#fff;cursor:pointer;">새로고침</button>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1.3fr;gap:16px;align-items:start;">
        <div style="background:#1a1a2e;border:1px solid #2a2a4a;border-radius:12px;padding:16px;">
          <div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap;">
            <select id="ef-status" style="padding:6px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;font-size:12px;">
              <option value="">전체 상태</option>
              <option value="pending">pending</option>
              <option value="in_progress">in_progress</option>
              <option value="done">done</option>
            </select>
          </div>
          <div id="ef-list"></div>
        </div>

        <div id="ef-detail" style="background:#1a1a2e;border:1px solid #2a2a4a;border-radius:12px;padding:16px;color:#888;">
          <div style="text-align:center;padding:40px 0;">왼쪽에서 카드를 선택하세요.</div>
        </div>
      </div>

      <div style="margin-top:16px;background:#1a1a2e;border:1px solid #2a2a4a;border-radius:12px;padding:16px;">
        <h3 style="color:#fff;margin:0 0 12px;font-size:14px;">📋 라우팅 표 (Phase 1 정적)</h3>
        <div id="ef-routing"></div>
      </div>

      <div id="ef-mock-modal" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:1000;align-items:center;justify-content:center;">
        <div style="background:#1a1a2e;border:1px solid #2a2a4a;border-radius:12px;padding:20px;width:540px;max-width:90vw;max-height:90vh;overflow-y:auto;">
          <h3 style="color:#fff;margin:0 0 12px;">🧪 Mock 자동 카드 생성</h3>
          <p style="color:#888;font-size:12px;margin:0 0 12px;">Week 3 E2E 검증용. 이 폼은 운영 데이터에 실제 자동 카드 1건을 생성합니다.</p>
          <form id="ef-mock-form">
            <div style="display:grid;gap:8px;">
              <div>
                <label style="color:#aaa;font-size:12px;">exception_type</label>
                <select id="ef-mock-type" required style="width:100%;padding:8px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;">
                  <option value="SKU_MATCH_FAILED">SKU_MATCH_FAILED</option>
                  <option value="AUTOMATION_FAILED">AUTOMATION_FAILED</option>
                  <option value="ADDRESS_INVALID">ADDRESS_INVALID</option>
                  <option value="MARGIN_RISK">MARGIN_RISK</option>
                  <option value="SUPPLIER_OUT_OF_STOCK">SUPPLIER_OUT_OF_STOCK</option>
                  <option value="LABEL_FAILED">LABEL_FAILED</option>
                </select>
              </div>
              <div>
                <label style="color:#aaa;font-size:12px;">severity</label>
                <select id="ef-mock-severity" style="width:100%;padding:8px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;">
                  <option value="low">low</option>
                  <option value="medium" selected>medium</option>
                  <option value="high">high</option>
                  <option value="critical">critical</option>
                </select>
              </div>
              <div>
                <label style="color:#aaa;font-size:12px;">dedupe_key (동일 key 재트리거 시 새 카드 생성 안 됨)</label>
                <input id="ef-mock-dedupe" placeholder="예: sku_match_failed:ebay:ORD-001:line1" style="width:100%;padding:8px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;font-family:monospace;">
              </div>
              <div>
                <label style="color:#aaa;font-size:12px;">memo (선택)</label>
                <input id="ef-mock-memo" placeholder="카드 본문 텍스트" style="width:100%;padding:8px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;">
              </div>
              <div>
                <label style="color:#aaa;font-size:12px;">context (JSON. token/email/phone 등은 backend redact 통과)</label>
                <textarea id="ef-mock-context" rows="6" placeholder='{ "marketplace": "ebay", "external_order_id": "ORD-001", "buyer_email": "test@example.com", "api_token": "sk_will_be_redacted" }' style="width:100%;padding:8px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;font-family:monospace;font-size:12px;"></textarea>
              </div>
            </div>
            <div style="margin-top:14px;display:flex;justify-content:flex-end;gap:8px;">
              <button type="button" id="ef-mock-cancel" style="padding:8px 14px;background:#37474f;border:none;border-radius:6px;color:#fff;cursor:pointer;">취소</button>
              <button type="submit" style="padding:8px 14px;background:#1565c0;border:none;border-radius:6px;color:#fff;cursor:pointer;font-weight:600;">생성</button>
            </div>
          </form>
        </div>
      </div>
    `;

    document.getElementById('ef-refresh').addEventListener('click', refresh);
    document.getElementById('ef-status').addEventListener('change', refresh);
    document.getElementById('ef-mock-btn').addEventListener('click', () => {
      document.getElementById('ef-mock-modal').style.display = 'flex';
    });
    document.getElementById('ef-mock-cancel').addEventListener('click', () => {
      document.getElementById('ef-mock-modal').style.display = 'none';
    });
    document.getElementById('ef-mock-form').addEventListener('submit', onMockSubmit);
  }

  async function loadRouting() {
    try {
      const res = await fetch('/api/exception-routing');
      const json = await res.json();
      if (!res.ok) throw new Error(json.error || 'load failed');
      routing = json.data || [];
      renderRouting();
    } catch (_) { /* silent */ }
  }

  function renderRouting() {
    const el = document.getElementById('ef-routing');
    if (!el) return;
    if (routing.length === 0) {
      el.innerHTML = '<div style="color:#888;font-size:12px;">라우팅 데이터 없음</div>';
      return;
    }
    el.innerHTML = `
      <table style="width:100%;border-collapse:collapse;font-size:12px;">
        <thead><tr style="color:#aaa;border-bottom:1px solid #2a2a4a;">
          <th style="padding:6px;text-align:left;">exception_type</th>
          <th style="padding:6px;text-align:left;">scope</th>
          <th style="padding:6px;text-align:left;">기본 제목</th>
        </tr></thead>
        <tbody>${routing.map(r => `
          <tr style="border-top:1px solid #2a2a4a;">
            <td style="padding:6px;font-family:monospace;color:#81d4fa;">${esc(r.exception_type)}</td>
            <td style="padding:6px;color:#aaa;">${esc(r.scope)}</td>
            <td style="padding:6px;color:#fff;">${esc(r.title)}</td>
          </tr>
        `).join('')}</tbody>
      </table>
    `;
  }

  async function refresh() {
    const status = document.getElementById('ef-status')?.value || '';
    const params = new URLSearchParams({ autoGenerated: 'true' });
    if (status) params.set('status', status);
    try {
      const res = await fetch('/api/tasks?' + params.toString());
      const json = await res.json();
      if (!res.ok) throw new Error(json.error || 'load failed');
      cards = json.data || [];
      renderList();
      if (openTaskId) {
        const c = cards.find(x => x.id === openTaskId);
        if (c) renderDetail(c);
      }
    } catch (e) {
      document.getElementById('ef-list').innerHTML =
        `<div style="padding:20px;color:#ef9a9a;">로드 실패: ${esc(e.message)}</div>`;
    }
  }

  function renderList() {
    const el = document.getElementById('ef-list');
    if (cards.length === 0) {
      el.innerHTML = '<div style="padding:20px;color:#888;font-size:13px;">자동 예외 카드가 없습니다.</div>';
      return;
    }
    el.innerHTML = cards.map(c => {
      const sev = SEVERITY_COLORS[c.severity] || SEVERITY_COLORS.medium;
      const isActive = c.id === openTaskId;
      return `
        <div class="ef-card" data-id="${c.id}" style="
          padding:10px 12px;border:1px solid ${isActive ? '#81d4fa' : '#2a2a4a'};
          border-radius:8px;margin-bottom:8px;cursor:pointer;
          background:${isActive ? '#0a1a2e' : '#0f0f23'};
        ">
          <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-bottom:4px;">
            <span style="background:#37474f;color:#aaa;padding:2px 6px;border-radius:3px;font-size:10px;font-weight:600;">AUTO</span>
            <span style="background:${sev.bg};color:${sev.fg};padding:2px 6px;border-radius:3px;font-size:10px;font-weight:600;">${esc(c.severity || 'medium')}</span>
            <span style="background:#1a3a4a;color:#64b5f6;padding:2px 6px;border-radius:3px;font-size:10px;font-family:monospace;">${esc(c.exception_type || '?')}</span>
            <span style="margin-left:auto;color:${c.status === 'done' ? '#69f0ae' : '#aaa'};font-size:11px;">${esc(c.status)}</span>
          </div>
          <div style="color:#fff;font-size:13px;margin-bottom:4px;">${esc(c.title)}</div>
          ${c.dedupe_key ? `<div style="color:#666;font-size:10px;font-family:monospace;">${esc(c.dedupe_key)}</div>` : ''}
          <div style="color:#666;font-size:11px;margin-top:4px;">${fmtDate(c.created_at)}${c.related_sku_id ? ` · sku#${c.related_sku_id}` : ''}</div>
        </div>
      `;
    }).join('');

    el.querySelectorAll('.ef-card').forEach(div => {
      div.addEventListener('click', () => {
        const id = parseInt(div.dataset.id, 10);
        const c = cards.find(x => x.id === id);
        if (c) {
          openTaskId = id;
          renderList();
          renderDetail(c);
        }
      });
    });
  }

  function renderDetail(c) {
    const el = document.getElementById('ef-detail');
    const sev = SEVERITY_COLORS[c.severity] || SEVERITY_COLORS.medium;
    const myRec = (c.recipients || []).find(r => r.userId === user.id);
    const canDone = myRec && myRec.status !== 'done';

    const recipientsHtml = (c.recipients && c.recipients.length > 0)
      ? `<div style="margin-bottom:12px;">
          <div style="color:#aaa;font-size:11px;margin-bottom:4px;">수신자 (${c.recipients.length})</div>
          ${c.recipients.map(r => `
            <div style="display:flex;justify-content:space-between;padding:4px 8px;background:#0f0f23;border-radius:4px;margin-bottom:2px;font-size:12px;">
              <span style="color:#fff;">${esc(r.userName || ('user#' + r.userId))}${r.userId === user.id ? ' (나)' : ''}</span>
              <span style="color:${r.status === 'done' ? '#69f0ae' : '#aaa'};">${esc(r.status)}${r.completedAt ? ` · ${fmtDate(r.completedAt)}` : ''}</span>
            </div>
          `).join('')}
        </div>`
      : '';

    el.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:12px;">
        <div>
          <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-bottom:6px;">
            <span style="background:#37474f;color:#aaa;padding:3px 8px;border-radius:3px;font-size:11px;font-weight:600;">AUTO</span>
            <span style="background:${sev.bg};color:${sev.fg};padding:3px 8px;border-radius:3px;font-size:11px;font-weight:600;">${esc(c.severity || 'medium')}</span>
            <span style="background:#1a3a4a;color:#64b5f6;padding:3px 8px;border-radius:3px;font-size:11px;font-family:monospace;">${esc(c.exception_type || '?')}</span>
          </div>
          <h2 style="color:#fff;font-size:16px;margin:0;">${esc(c.title)}</h2>
        </div>
        <div style="display:flex;gap:6px;">
          ${canDone ? `<button id="ef-done-btn" style="padding:6px 12px;background:#1b5e20;border:none;border-radius:4px;color:#fff;cursor:pointer;font-size:12px;">완료 처리</button>` : ''}
        </div>
      </div>

      ${c.dedupe_key ? `<div style="margin-bottom:8px;color:#666;font-size:11px;font-family:monospace;">dedupe: ${esc(c.dedupe_key)}</div>` : ''}
      ${c.memo ? `<div style="margin-bottom:12px;padding:8px;background:#0f0f23;border-radius:4px;color:#ccc;font-size:13px;">${esc(c.memo)}</div>` : ''}

      <div style="margin-bottom:12px;font-size:12px;color:#aaa;">
        생성: ${fmtDate(c.created_at)}
        ${c.related_sku_id ? ` · 관련 SKU: <span style="color:#81d4fa;">#${c.related_sku_id}</span>` : ''}
        ${c.related_order_id ? ` · 관련 주문: <span style="color:#81d4fa;">#${c.related_order_id}</span>` : ''}
      </div>

      ${recipientsHtml}

      ${renderContextSection(c.context)}
    `;

    if (canDone) {
      document.getElementById('ef-done-btn').addEventListener('click', () => onMarkDone(c.id));
    }
  }

  // 2026-07-10: 우선순위 SKU context 를 표 형태 + 클릭 이동으로 렌더.
  // priority_skus 배열 있으면 표, 없으면 JSON 그대로.
  function renderContextSection(ctx) {
    if (!ctx || typeof ctx !== 'object' || Object.keys(ctx).length === 0) {
      return `<div style="margin-bottom:8px;">
        <div style="color:#aaa;font-size:11px;margin-bottom:4px;">context</div>
        <div style="background:#0f0f23;color:#666;padding:10px;border-radius:6px;font-size:12px;">(비어있음)</div>
      </div>`;
    }
    const skus = Array.isArray(ctx.priority_skus) ? ctx.priority_skus : null;
    if (!skus || skus.length === 0) {
      return `<div style="margin-bottom:8px;">
        <div style="color:#aaa;font-size:11px;margin-bottom:4px;">context (JSON · backend redact 통과)</div>
        <pre style="background:#0f0f23;color:#cfd8dc;padding:10px;border-radius:6px;font-size:11px;overflow-x:auto;max-height:280px;margin:0;">${esc(JSON.stringify(ctx, null, 2))}</pre>
      </div>`;
    }
    // priority_skus 표 렌더 (사장님이 SKU 클릭 → SKU 마스터로 이동해 인라인 편집)
    const totalUsd = ctx.total_estimated_revenue_usd || ctx.total_potential_impact_usd || 0;
    const summary = `우선순위 SKU <strong>${skus.length}</strong>개 · 누적 규모 <strong>$${Number(totalUsd).toLocaleString()}</strong>`;
    // 2026-07-10 사장님 지침: 전체 SKU 를 SKU 마스터에서 한 번에 열기.
    //   URL 파라미터 ?skus=A,B,C 로 SKU 마스터가 정확 일치 필터.
    const skuCsv = skus.map((s) => s.sku).filter(Boolean).join(',');
    const bulkOpenBtn = skuCsv
      ? `<button onclick="(function(){ const u=new URL(location.href); u.searchParams.set('page','sku-master'); u.searchParams.set('skus','${skuCsv.replace(/'/g, "\\'")}'); history.pushState({}, '', u); navigateTo('sku-master'); })(); return false;" style="padding:6px 12px;background:#2e7d32;border:none;border-radius:4px;color:#fff;cursor:pointer;font-size:12px;font-weight:600;">🚀 SKU 마스터에 ${skus.length}개 일괄 열기</button>`
      : '';
    const rows = skus.map((s, i) => {
      const scale = s.estimated_revenue_usd != null ? `$${Number(s.estimated_revenue_usd).toLocaleString()}` : (s.diff != null ? `+$${s.diff}` : '-');
      const sold = s.sales_count != null ? s.sales_count : (s.competitor_sold != null ? s.competitor_sold : '-');
      const price = s.price_usd != null ? `$${s.price_usd}` : (s.my_price != null ? `$${s.my_price}` : '-');
      const skuLabel = esc(s.sku || '');
      // SKU 마스터 페이지로 이동 (검색어 = SKU) — dashboard.js navigateTo 사용
      const linkOnclick = `navigateTo('sku-master'); setTimeout(() => { const inp=document.getElementById('sm-search'); if(inp){inp.value='${skuLabel.replace(/'/g,"\\'")}'; inp.dispatchEvent(new Event('input',{bubbles:true})); } }, 300); return false;`;
      return `<tr style="border-bottom:1px solid #1a1a2e;">
        <td style="padding:6px 8px;color:#888;font-size:11px;text-align:right;">${i + 1}</td>
        <td style="padding:6px 8px;font-family:monospace;font-size:11px;">
          <a href="#" onclick="${linkOnclick}" style="color:#81d4fa;text-decoration:none;">${skuLabel}</a>
        </td>
        <td style="padding:6px 8px;color:#fff;font-size:11px;max-width:280px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${esc(s.title || '')}">${esc((s.title || '').slice(0, 60))}</td>
        <td style="padding:6px 8px;color:#aaa;font-size:11px;text-align:right;">${sold}</td>
        <td style="padding:6px 8px;color:#aaa;font-size:11px;text-align:right;">${price}</td>
        <td style="padding:6px 8px;font-weight:700;color:#69f0ae;font-size:11px;text-align:right;">${scale}</td>
        <td style="padding:6px 8px;color:#ef9a9a;font-size:10px;">${esc(s.missing || '')}</td>
      </tr>`;
    }).join('');
    return `
      <div style="margin-bottom:12px;padding:10px;background:#0d2818;border-left:3px solid #2e7d32;border-radius:4px;font-size:12px;color:#c5e1a5;">
        <div style="margin-bottom:8px;">📌 ${summary}.</div>
        <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;">${bulkOpenBtn}
        <span style="color:#888;font-size:11px;">아래 표에서 SKU 개별 클릭 시 그 SKU 만 필터.</span></div>
      </div>
      <div style="margin-bottom:8px;">
        <div style="color:#aaa;font-size:11px;margin-bottom:4px;">우선순위 SKU 목록 (context.priority_skus)</div>
        <div style="max-height:400px;overflow:auto;background:#0f0f23;border-radius:6px;">
          <table style="width:100%;border-collapse:collapse;">
            <thead style="position:sticky;top:0;background:#0f0f23;">
              <tr style="border-bottom:1px solid #333;color:#aaa;font-size:11px;">
                <th style="padding:6px 8px;text-align:right;">#</th>
                <th style="padding:6px 8px;text-align:left;">SKU</th>
                <th style="padding:6px 8px;text-align:left;">제목</th>
                <th style="padding:6px 8px;text-align:right;">판매</th>
                <th style="padding:6px 8px;text-align:right;">단가</th>
                <th style="padding:6px 8px;text-align:right;">규모</th>
                <th style="padding:6px 8px;text-align:left;">미입력</th>
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
        </div>
      </div>
    `;
  }

  async function onMarkDone(taskId) {
    const note = prompt('완료 코멘트 (필수)', '확인 완료');
    if (!note || !note.trim()) return;
    try {
      const res = await fetch('/api/tasks/' + taskId, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: 'done', completionNote: note.trim() }),
      });
      const json = await res.json();
      if (!res.ok) throw new Error(json.error || 'update failed');
      await refresh();
    } catch (err) { alert('완료 처리 실패: ' + err.message); }
  }

  async function onMockSubmit(e) {
    e.preventDefault();
    let context = {};
    const ctxRaw = document.getElementById('ef-mock-context').value.trim();
    if (ctxRaw) {
      try { context = JSON.parse(ctxRaw); }
      catch (_) { alert('context 가 유효한 JSON 이 아닙니다'); return; }
    }
    const body = {
      exceptionType: document.getElementById('ef-mock-type').value,
      severity:      document.getElementById('ef-mock-severity').value,
      dedupeKey:     document.getElementById('ef-mock-dedupe').value.trim() || null,
      memo:          document.getElementById('ef-mock-memo').value.trim() || null,
      context,
    };
    try {
      const res = await fetch('/api/exception-routing/mock', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      const json = await res.json();
      if (!res.ok) throw new Error(json.error || 'mock failed');
      document.getElementById('ef-mock-modal').style.display = 'none';
      e.target.reset();
      await refresh();
      if (json.deduped) {
        alert('동일 dedupe_key 의 활성 카드가 이미 존재 — 신규 생성 안 함 (dedupe 동작 확인).');
      } else {
        // 신규 카드 자동 선택
        openTaskId = json.taskId;
        renderList();
        const c = cards.find(x => x.id === openTaskId);
        if (c) renderDetail(c);
      }
    } catch (err) { alert('Mock 생성 실패: ' + err.message); }
  }

  window.pmcExceptionFilter = { load };
})();
